import{_ as n,c as s,o as a,a as t}from"./app.1e429f93.js";const m='{"title":"Validation Rules","description":"","frontmatter":{},"headers":[{"level":2,"title":"Object with Options API","slug":"object-with-options-api"},{"level":2,"title":"Function with Options API","slug":"function-with-options-api"},{"level":2,"title":"Object with Composition API","slug":"object-with-composition-api"},{"level":3,"title":"Computed function with Composition API","slug":"computed-function-with-composition-api"}],"relativePath":"api/rules.md","lastUpdated":1777558301322}',p={},o=t(`<h1 id="validation-rules" tabindex="-1">Validation Rules <a class="header-anchor" href="#validation-rules" aria-hidden="true">#</a></h1><p>Validations can be defined in a few ways, each has its PROs over others.</p><h2 id="object-with-options-api" tabindex="-1">Object with Options API <a class="header-anchor" href="#object-with-options-api" aria-hidden="true">#</a></h2><p>Vuelidate 0.x supported defining rules as an object, and we kept this functionality, though it is limited compared to the other methods below.</p><div class="language-vue"><pre><code>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function-variable function">data</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span>
    <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token literal-property property">validations</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><h2 id="function-with-options-api" tabindex="-1">Function with Options API <a class="header-anchor" href="#function-with-options-api" aria-hidden="true">#</a></h2><p>A more flexible way to create validation rules is to use a function for your rules. This allows you to access and pass the current component state as params to other validators.</p><div class="language-vue"><pre><code>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function-variable function">data</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span>
    <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
    <span class="token literal-property property">confirmPassword</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span>
      <span class="token literal-property property">confirmPassword</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">sameAs</span><span class="token operator">:</span> <span class="token function">sameAs</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>password<span class="token punctuation">)</span> <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><h2 id="object-with-composition-api" tabindex="-1">Object with Composition API <a class="header-anchor" href="#object-with-composition-api" aria-hidden="true">#</a></h2><p>Rules can be defined as objects in Composition API. This works great for simpler forms and rules that are mostly static.</p><div class="language-js"><pre><code><span class="token keyword">const</span> password <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> confirmPassword <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// inside setup</span>
<span class="token keyword">const</span> rules <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token literal-property property">confirmPassword</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">sameAs</span><span class="token operator">:</span> <span class="token function">sameAs</span><span class="token punctuation">(</span>password<span class="token punctuation">)</span> <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token keyword">const</span> v$ <span class="token operator">=</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span>rules<span class="token punctuation">,</span> <span class="token punctuation">{</span> password<span class="token punctuation">,</span> confirmPassword <span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you are using a <code>reactive</code> state and need to pass state as props to validators, then use the method below, or you will lose reactivity</p></div><h3 id="computed-function-with-composition-api" tabindex="-1">Computed function with Composition API <a class="header-anchor" href="#computed-function-with-composition-api" aria-hidden="true">#</a></h3><p>Using a computed function allows your validation rules to be reactive and update with the state inside. This means that props passed from reactive states are kept reactive, rules can morph entirely.</p><div class="language-js"><pre><code><span class="token comment">// inside setup</span>
<span class="token comment">// state</span>
<span class="token keyword">const</span> state <span class="token operator">=</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">confirmPassword</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// rules</span>
<span class="token keyword">const</span> rules <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>someBoolean<span class="token punctuation">.</span>value<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// rules can change drastically</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token punctuation">{</span> someValidator <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">return</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">password</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token literal-property property">confirmPassword</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">sameAs</span><span class="token operator">:</span> <span class="token function">sameAs</span><span class="token punctuation">(</span>state<span class="token punctuation">.</span>password<span class="token punctuation">)</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> v$ <span class="token operator">=</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span>rules<span class="token punctuation">,</span> state<span class="token punctuation">)</span>
</code></pre></div>`,15),e=[o];function c(i,l,r,u,k,d){return a(),s("div",null,e)}var w=n(p,[["render",c]]);export{m as __pageData,w as default};
